-- Monthly fund history (from custodian statements)
CREATE TABLE public.fund_monthly_history (
  month DATE PRIMARY KEY,
  beginning_balance NUMERIC(14,2) NOT NULL DEFAULT 0,
  market_change NUMERIC(14,2) NOT NULL DEFAULT 0,
  dividends NUMERIC(14,2) NOT NULL DEFAULT 0,
  interest NUMERIC(14,2) NOT NULL DEFAULT 0,
  deposits NUMERIC(14,2) NOT NULL DEFAULT 0,
  withdrawals NUMERIC(14,2) NOT NULL DEFAULT 0,
  net_advisory_fees NUMERIC(14,2) NOT NULL DEFAULT 0,
  ending_balance NUMERIC(14,2) NOT NULL DEFAULT 0,
  is_transition BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
GRANT SELECT ON public.fund_monthly_history TO anon, authenticated;
GRANT ALL ON public.fund_monthly_history TO service_role;
ALTER TABLE public.fund_monthly_history ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read fund monthly history"
  ON public.fund_monthly_history FOR SELECT
  TO anon, authenticated USING (true);

CREATE TABLE public.benchmark_monthly (
  month DATE NOT NULL,
  symbol TEXT NOT NULL,
  close NUMERIC(14,4) NOT NULL,
  return_pct NUMERIC(10,4),
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (month, symbol)
);
GRANT SELECT ON public.benchmark_monthly TO anon, authenticated;
GRANT ALL ON public.benchmark_monthly TO service_role;
ALTER TABLE public.benchmark_monthly ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public read benchmark monthly"
  ON public.benchmark_monthly FOR SELECT
  TO anon, authenticated USING (true);

